export type OrderState =
  | "PENDING"
  | "CONFIRMED"
  | "SHIPPED"
  | "DELIVERED"
  | "CANCELLED";

// AC1: Valid transitions map
const VALID_TRANSITIONS: Record<OrderState, ReadonlySet<OrderState>> = {
  PENDING: new Set(["CONFIRMED", "CANCELLED"]),
  CONFIRMED: new Set(["SHIPPED", "CANCELLED"]),
  SHIPPED: new Set(["DELIVERED"]),
  DELIVERED: new Set(), // AC4: terminal state
  CANCELLED: new Set(), // AC3: terminal state
};

export class InvalidTransitionError extends Error {
  readonly code = "INVALID_TRANSITION";

  constructor(from: OrderState, to: OrderState) {
    super(`Cannot transition from ${from} to ${to}`);
    this.name = "InvalidTransitionError";
  }
}

export class OrderStateMachine {
  /**
   * Attempt a state transition.
   * @returns the new state if the transition is valid
   * @throws InvalidTransitionError (with code "INVALID_TRANSITION") for invalid transitions
   */
  transition(currentState: OrderState, targetState: OrderState): OrderState {
    if (!VALID_TRANSITIONS[currentState].has(targetState)) {
      throw new InvalidTransitionError(currentState, targetState);
    }
    return targetState;
  }
}

